import json
import time
import hashlib
from functools import wraps
from flask import Flask, request, jsonify
from pymemcache.client.base import Client
from pymemcache.client.retrying import RetryingClient
from pymemcache.exceptions import MemcacheUnexpectedCloseError


app = Flask(__name__)

# Configuration
app.config['MEMCACHED_HOST'] = 'localhost'
app.config['MEMCACHED_PORT'] = 11211
app.config['DEFAULT_CACHE_TTL'] = 300  # 5 minutes
app.config['API_CACHE_TTL'] = 60  # 1 minute
app.config['DB_CACHE_TTL'] = 600  # 10 minutes


# JSON serializer/deserializer for Memcached
def json_serializer(key, value):
    if isinstance(value, str):
        return value, 1
    return json.dumps(value), 2


def json_deserializer(key, value, flags):
    if flags == 1:
        return value.decode('utf-8')
    if flags == 2:
        return json.loads(value.decode('utf-8'))
    raise Exception("Unknown serialization format")


# Initialize Memcached client with retry logic
def get_memcached_client():
    base_client = Client(
        (app.config['MEMCACHED_HOST'], app.config['MEMCACHED_PORT']),
        serializer=json_serializer,
        deserializer=json_deserializer,
        connect_timeout=5,
        timeout=3,
        no_delay=True,
    )
    client = RetryingClient(
        base_client,
        attempts=3,
        retry_delay=0.1,
        retry_for=[MemcacheUnexpectedCloseError, ConnectionRefusedError, OSError],
    )
    return client


cache_client = get_memcached_client()


# --- Cache Helper Functions ---

def generate_cache_key(prefix, *args, **kwargs):
    """Generate a consistent cache key from prefix and arguments."""
    key_data = f"{prefix}:{json.dumps(args, sort_keys=True)}:{json.dumps(kwargs, sort_keys=True)}"
    key_hash = hashlib.md5(key_data.encode()).hexdigest()
    return f"{prefix}:{key_hash}"


def cache_get(key):
    """Get a value from cache, returns None if not found or on error."""
    try:
        result = cache_client.get(key)
        if result is not None:
            app.logger.debug(f"Cache HIT for key: {key}")
        else:
            app.logger.debug(f"Cache MISS for key: {key}")
        return result
    except Exception as e:
        app.logger.error(f"Memcached GET error for key {key}: {e}")
        return None


def cache_set(key, value, ttl=None):
    """Set a value in cache with optional TTL."""
    if ttl is None:
        ttl = app.config['DEFAULT_CACHE_TTL']
    try:
        cache_client.set(key, value, expire=ttl)
        app.logger.debug(f"Cache SET for key: {key} with TTL: {ttl}s")
        return True
    except Exception as e:
        app.logger.error(f"Memcached SET error for key {key}: {e}")
        return False


def cache_delete(key):
    """Delete a value from cache."""
    try:
        cache_client.delete(key)
        app.logger.debug(f"Cache DELETE for key: {key}")
        return True
    except Exception as e:
        app.logger.error(f"Memcached DELETE error for key {key}: {e}")
        return False


def cache_invalidate_pattern(prefix):
    """
    Invalidate cache entries by tracking keys with a prefix.
    Since Memcached doesn't support pattern deletion natively,
    we maintain a set of keys per prefix.
    """
    try:
        tracked_keys = cache_client.get(f"_tracked:{prefix}")
        if tracked_keys:
            for key in tracked_keys:
                cache_client.delete(key)
            cache_client.delete(f"_tracked:{prefix}")
            app.logger.debug(f"Invalidated all keys with prefix: {prefix}")
        return True
    except Exception as e:
        app.logger.error(f"Cache invalidation error for prefix {prefix}: {e}")
        return False


def track_cache_key(prefix, key):
    """Track a cache key under a prefix for bulk invalidation."""
    try:
        tracked_key = f"_tracked:{prefix}"
        existing = cache_client.get(tracked_key)
        if existing is None:
            existing = []
        if key not in existing:
            existing.append(key)
        cache_client.set(tracked_key, existing, expire=app.config['DB_CACHE_TTL'] * 2)
    except Exception as e:
        app.logger.error(f"Error tracking cache key: {e}")


