def cached_route(ttl=None, key_prefix=None):
    """Decorator to cache Flask route responses."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            prefix = key_prefix or f.__name__
            cache_key = generate_cache_key(
                prefix,
                request.path,
                request.args.to_dict(),
            )

            cached_result = cache_get(cache_key)
            if cached_result is not None:
                response = cached_result.copy()
                response['_cache'] = 'HIT'
                return jsonify(response)

            result = f(*args, **kwargs)

            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data = result
                status_code = 200

            if isinstance(response_data, dict):
                cache_ttl = ttl or app.config['API_CACHE_TTL']
                cache_set(cache_key, response_data, ttl=cache_ttl)
                track_cache_key(prefix, cache_key)
                response_data['_cache'] = 'MISS'
                return jsonify(response_data), status_code

            return result
        return decorated_function
    return decorator


def cached_db_query(ttl=None, key_prefix="db"):
    """Decorator to cache database query function results."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = generate_cache_key(
                f"{key_prefix}:{f.__name__}",
                *args,
                **kwargs,
            )

            cached_result = cache_get(cache_key)
            if cached_result is not None:
                return cached_result

            result = f(*args, **kwargs)

            cache_ttl = ttl or app.config['DB_CACHE_TTL']
            cache_set(cache_key, result, ttl=cache_ttl)
            track_cache_key(key_prefix, cache_key)

            return result
        return decorated_function
    return decorator


